import axios from "axios";
import { useEffect, useState } from "react";
import { useParams, useSearchParams } from "react-router-dom";
import { SEO } from "../utils/SEO";

const BreadcrumbThree = () => {
    const { id, slug } = useParams();
  const [decodedID,setDecodedID] = useState("");
  const [centre, setCentre] = useState(null);

     useEffect(() => {
    const fetchDecrtyptedID = async () => {
      try {
        const response = await axios.get(
          `${process.env.REACT_APP_BACKEND_URL}/api/decrypt/${id}`
        );

       setDecodedID(response.data.decodedId);
       
      } catch (error) {
        console.error("Failed to fetch centre:", error);
      }
    };

    fetchDecrtyptedID();
  }, [id]);

  useEffect(() => {
    const fetchCentre = async () => {
      try {
        const response = await axios.get(
          `${process.env.REACT_APP_BACKEND_URL}/api/centres/decrypted/${id}`
        );
        setCentre(response.data);
      } catch (error) {
        console.error("Failed to fetch centre:", error);
      }
    };

    fetchCentre();
  }, [id]);

  const [serDocApp, setSerDocApp] = useState();
  useEffect(() => {
    const fetchDetails = async () => {
      try {
        const response = await axios.get(
          `${process.env.REACT_APP_BACKEND_URL}/api/centres/stats?centreId=${decodedID}`
        );

        setSerDocApp(response.data);
      } catch (error) {
        console.error("Failed to fetch ");
      }
    };
    fetchDetails();
  }, [decodedID]);

      const toTitleCase = (str = "") => {
    return str
      .toLowerCase()
      .split(" ")
      .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
      .join(" ");
  };

  

  let seoTitle = centre?.centreName

  ? `${toTitleCase(centre?.centreName)}`
  : "Book Healthcare Services Online | 4ceps";

if (seoTitle.length > 70) {
  const trimmed = seoTitle.substring(0, 70);
  seoTitle = trimmed.substring(0, trimmed.lastIndexOf(" ")) + "...";
}

  // FIXED: Uncommented the description logic
 let seoDescription = centre?.aboutCentre
  ? centre?.aboutCentre
  : "Book trusted healthcare services near you with 4ceps. Find top hospitals, clinics, specialists, diagnostics & appointments easily online.";

if (seoDescription.length > 165) {
  const trimmed = seoDescription.substring(0, 165);
  seoDescription = trimmed.substring(0, trimmed.lastIndexOf(" ")) + "...";
}

const can = window.location.href;

  return (
    <>
        {centre && (
        <SEO
          title={seoTitle}
          description={seoDescription}
          url={can}
        />

      )}
    <section className="breadcrumb-three section-bg position-relative z-index-1 overflow-hidden">
      <img
        src="/assets/images/gradients/Bg.png"
        alt=""
        className="bg--gradient" loading="lazy"
      />

      <div className="container container-two">
        <div className="breadcrumb-three-content border-bottom border-color">
          <div className="breadcrumb-three-content__inner">
            <div className="breadcrumb-three-content__left">
              <div className="flx-between align-items-end gap-3">
                <div className="author-profile d-flex gap-2 flex-column">
                  <div className="author-profile__thumb flex-shrink-0">
                    <img
                      src={centre?.logo}
                      alt="logoImage"
                      style={{
                        width: "120px",
                        height: "120px",
                        borderRadius: "10%",
                        objectFit: "cover",
                      }}
                      loading="lazy"
                    />
                  </div>

                  <div className="author-profile__info">
                    <h1 className="author-profile__name mb-2">
                      {centre?.centreName}
                    </h1>

                    <span className="author-profile__membership font-14">
                      Member Since{" "}
                      <span id="member-since">
                        {centre?.createdAt
                          ? new Date(centre.createdAt).toLocaleString(
                              "default",
                              {
                                month: "long",
                                year: "numeric",
                              }
                            )
                          : ""}
                      </span>
                    </span>
                  </div>
                </div>

                {/* Stats start */}
                <div className="breadcrumb-three-content__right flex-shrink-0  d-flex align-items-center gap-4 gap-lg-5">
                  

                  <div className="sales">
                    <span className="sales__text mb-1 text-heading fw-500">
                      Services
                    </span>

                    <h5 className="sales__amount mb-0">
                      {serDocApp?.totalServices}
                    </h5>
                  </div>

                  <div className="sales">
                    <span className="sales__text mb-1 text-heading fw-500">
                      Doctors
                    </span>

                    <h5 className="sales__amount mb-0">
                      {serDocApp?.totalDoctors}
                    </h5>
                  </div>

                  <div className="sales">
                    <span className="sales__text mb-1 text-heading fw-500">
                      Appointments
                    </span>

                    <h5 className="sales__amount mb-0">
                      {serDocApp?.totalBookings}
                    </h5>
                  </div>
                </div>
                {/* Stats end */}
              </div>
            </div>
          </div>

          {/* Tabs */}
          <ul
            className="nav tab-bordered nav-pills mt-4"
            id="pills-tabbs"
            role="tablist"
          >
            <li className="nav-item" role="presentation">
              <button
                className="nav-link active"
                id="pills-profile-tab"
                data-bs-toggle="pill"
                data-bs-target="#pills-profile"
                type="button"
                role="tab"
                aria-controls="pills-profile"
                aria-selected="true"
              >
                Profile
              </button>
            </li>

            <li className="nav-item" role="presentation">
              <button
                className="nav-link"
                id="pills-portfolio-tab"
                data-bs-toggle="pill"
                data-bs-target="#pills-portfolio"
                type="button"
                role="tab"
                aria-controls="pills-portfolio"
                aria-selected="false"
              >
                Services{" "}
              </button>
            </li>
            <li className="nav-item" role="presentation">
              <button
                className="nav-link"
                id="pills-package-tab"
                data-bs-toggle="pill"
                data-bs-target="#pills-package"
                type="button"
                role="tab"
                aria-controls="pills-package"
                aria-selected="false"
              >
                Health Checkup Packages{" "}
              </button>
            </li>

             <li className="nav-item" role="presentation">
              <button
                className="nav-link "
                id="pills-doctors-tab"
                data-bs-toggle="pill"
                data-bs-target="#pills-doctors"
                type="button"
                role="tab"
                aria-controls="pills-doctors"
                aria-selected="false"
              >
               Doctors
              </button>
            </li>
            <li className="nav-item" role="presentation">
              <button
                className="nav-link"
                id="pills-gallery-tab"
                data-bs-toggle="pill"
                data-bs-target="#pills-gallery"
                type="button"
                role="tab"
                aria-controls="pills-gallery"
                aria-selected="false"
              >
                Gallery{" "}
              </button>
            </li>
          </ul>
        </div>
      </div>
    </section>
    </>
  );
};

export default BreadcrumbThree;
