const fetchPackages = async (page = 1) => {
  try {
    const res = await axios.get(
      `${process.env.REACT_APP_BACKEND_URL}/api/packages/${decodedID}`,
      {
        params: {
          page: page,
          limit: packagesPerPage
        }
      }
    );


    // Handle paginated response
    if (res.data.packages) {
      setPackages(res.data.packages);
      setCurrentPackagePage(res.data.currentPage || page);
      setTotalPackagePages(res.data.totalPages || 1);
      setTotalPackages(res.data.totalPackages || 0);
    } else if (Array.isArray(res.data)) {
      // Fallback for non-paginated response
      setPackages(res.data);
      setTotalPackagePages(Math.ceil(res.data.length / packagesPerPage));
      setTotalPackages(res.data.length);
    }
  } catch (err) {
    console.error("Failed to load package details", err.message);
    setPackages([]);
    setTotalPackagePages(1);
  }
};

